mapper.update:
UPDATE pet_vaccine_record
vaccine_name = #{vaccineName}, vaccine_date = #{vaccineDate}, next_date = #{nextDate}, operator_name = #{operatorName}, remark = #{remark},
WHERE id = #{id}

mapper.select:
SELECT v.id, v.vaccine_name as vaccineName, DATE_FORMAT(v.vaccine_date, '%Y-%m-%d') as vaccineDate, DATE_FORMAT(v.next_date, '%Y-%m-%d') as nextDate, DATE_FORMAT(v.create_time, '%Y-%m-%d %H:%i:%s') as createTime, v.operator_name as operatorName, v.remark, p.id as petId, p.name as petName, u.id as ownerId, u.username as ownerName, u.nickname as ownerNickname, i.item_name as vaccineStockName, i.stock as currentStock FROM pet_vaccine_record v LEFT JOIN pet_profile p ON v.pet_id = p.id LEFT JOIN user u ON p.user_id = u.id LEFT JOIN inventory i ON v.inventory_id = i.id WHERE p.status = 1
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%') OR v.vaccine_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY v.create_time DESC LIMIT #{offset}, #{limit}

mapper.delete:
DELETE FROM pet_vaccine_record
WHERE id IN

    #{id}
